import type { VendorDashboard } from '../types';
const Card=({label,value,detail}:{label:string;value:string|number;detail:string})=><article className="rounded-xl border border-slate-200 bg-white p-5 shadow-sm dark:border-slate-700 dark:bg-slate-900"><p className="text-xs font-semibold uppercase tracking-wider text-slate-400">{label}</p><p className="mt-2 text-3xl font-bold tabular-nums text-slate-900 dark:text-white">{value}</p><p className="mt-1 text-xs text-slate-500 dark:text-slate-400">{detail}</p></article>;
export const SupplierStatistics=({data}:{data:VendorDashboard})=><div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-3"><Card label="Active Suppliers" value={data.active_suppliers} detail="Available for purchasing"/><Card label="Expiring Contracts" value={data.expiring_contracts} detail="Renewal or end date within 30 days"/><Card label="Average Rating" value={`${Number(data.average_supplier_rating).toFixed(2)} / 5`} detail="Latest supplier performance reviews"/></div>;
